@page "/apply"
@rendermode InteractiveServer
@using sv_cf2e3316faa24278a6c6a6327c46adb2.Models
@using sv_cf2e3316faa24278a6c6a6327c46adb2.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4">
    <h1 class="mb-4">Job Application</h1>

    @if (!_submitted)
    {
        <StepIndicator CurrentStep="_currentStep"
                       CompletedSteps="_completedSteps"
                       OnStepClicked="GoToStep" />

        <div class="card mt-4">
            <div class="card-body">
                @switch (_currentStep)
                {
                    case 1:
                        <StepPersonalInfo FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                                          FullNameChanged="v => _fullName = v"
                                          EmailChanged="v => _email = v"
                                          PhoneChanged="v => _phone = v"
                                          AddressChanged="v => _address = v"
                                          ValidationError="@_validationError"
                                          OnNext="NextFromPersonalInfo" />
                        break;

                    case 2:
                        <StepWorkHistory Entries="_workEntries"
                                         CurrentFlags="_currentJobFlags"
                                         ValidationError="@_validationError"
                                         OnBack="Back"
                                         OnNext="NextFromWorkHistory" />
                        break;

                    case 3:
                        <StepReferences References="_references"
                                        ValidationError="@_validationError"
                                        OnBack="Back"
                                        OnNext="NextFromReferences" />
                        break;

                    case 4:
                        <StepCoverLetter CoverLetter="@_coverLetter"
                                         CoverLetterChanged="v => _coverLetter = v"
                                         MaxLength="2000"
                                         OnBack="Back"
                                         OnNext="NextFromCoverLetter" />
                        break;

                    case 5:
                        <StepReview FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                                    WorkEntries="_workEntries" CurrentFlags="_currentJobFlags"
                                    References="_references" CoverLetter="@_coverLetter"
                                    IsSubmitting="_isSubmitting" SubmitError="@_submitError"
                                    OnEdit="GoToStep"
                                    OnSubmit="SubmitApplication" />
                        break;
                }
            </div>
        </div>
    }
    else
    {
        <div class="card mt-4">
            <div class="card-body text-center py-5">
                <div class="text-success mb-3" style="font-size:3rem;">✓</div>
                <h2 class="text-success">Application Submitted!</h2>
                <p class="lead mt-3">Your application has been received.</p>
                <p class="fs-5">Application ID: <strong>@_applicationId</strong></p>
                <p class="text-muted">Please save this ID for your records.</p>
            </div>
        </div>
    }
</div>

@code {
    private int _currentStep = 1;
    private HashSet<int> _completedSteps = new();

    // Step 1
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2
    private List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };
    private List<bool> _currentJobFlags = new() { false };

    // Step 3
    private List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4
    private string _coverLetter = "";

    // Shared
    private string? _validationError;
    private bool _isSubmitting;
    private string? _submitError;
    private bool _submitted;
    private int _applicationId;

    private void GoToStep(int step)
    {
        if (_completedSteps.Contains(step) || step == _currentStep)
        {
            _validationError = null;
            _currentStep = step;
        }
    }

    private void Back()
    {
        _validationError = null;
        _currentStep--;
    }

    private async Task NextFromPersonalInfo()
    {
        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email)
            || string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _validationError = "All fields are required.";
            return;
        }

        var emailValid = await ApplicationService.ValidateEmailAsync(_email);
        if (!emailValid)
        {
            _validationError = "Please enter a valid email address.";
            return;
        }

        _validationError = null;
        _completedSteps.Add(1);
        _currentStep = 2;
    }

    private void NextFromWorkHistory()
    {
        foreach (var entry in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title)
                || entry.StartDate == default)
            {
                _validationError = "Company, title, and start date are required for each position.";
                return;
            }
        }

        _validationError = null;
        _completedSteps.Add(2);
        _currentStep = 3;
    }

    private void NextFromReferences()
    {
        foreach (var r in _references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _validationError = "All fields are required for each reference.";
                return;
            }
        }

        _validationError = null;
        _completedSteps.Add(3);
        _currentStep = 4;
    }

    private void NextFromCoverLetter()
    {
        if (string.IsNullOrWhiteSpace(_coverLetter))
        {
            _validationError = "Cover letter is required.";
            return;
        }

        _validationError = null;
        _completedSteps.Add(4);
        _currentStep = 5;
    }

    private async Task SubmitApplication()
    {
        _isSubmitting = true;
        _submitError = null;

        try
        {
            var personal = new PersonalInfo(_fullName, _email, _phone, _address);
            var workHistory = new WorkHistory(_workEntries.Select((e, i) =>
                new WorkEntry(e.Company, e.Title, e.StartDate, _currentJobFlags[i] ? null : e.EndDate, e.Description)
            ).ToList());
            var refs = _references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var application = new JobApplication(personal, workHistory, refs, _coverLetter);

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public string Description { get; set; } = "";
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

@{
    var stepNames = new[] { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
}

<nav class="step-indicator d-flex align-items-center justify-content-between">
    @for (int i = 0; i < stepNames.Length; i++)
    {
        var step = i + 1;
        var isActive = step == CurrentStep;
        var isCompleted = CompletedSteps.Contains(step);
        var isFuture = !isActive && !isCompleted;
        var clickable = isCompleted;

        <div class="step-item text-center flex-fill @(isActive ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
             role="button"
             @onclick="() => { if (clickable) OnStepClicked.InvokeAsync(step); }">
            <div class="step-circle mx-auto mb-1 @(isActive ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")">
                @if (isCompleted)
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@step</span>
                }
            </div>
            <small class="@(isFuture ? "text-muted" : isActive ? "fw-bold text-primary" : "text-success")">@stepNames[i]</small>
        </div>

        @if (step < stepNames.Length)
        {
            <div class="step-connector flex-fill" style="height:2px;max-width:40px;">
                <hr class="m-0 @(CompletedSteps.Contains(step) ? "border-success" : "border-secondary")" style="border-width:2px;" />
            </div>
        }
    }
</nav>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.85rem;
    font-weight: bold;
}

.step-item.completed {
    cursor: pointer;
}

.step-item.future {
    opacity: 0.5;
}

@using static sv_cf2e3316faa24278a6c6a6327c46adb2.Components.Pages.Apply.Apply

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger">@ValidationError</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Position @(index + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Company <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="entry.Company" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="entry.Title" />
                </div>
            </div>

            <div class="row">
                <div class="col-md-4 mb-3">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" @bind="entry.StartDate" />
                </div>
                <div class="col-md-4 mb-3">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" @bind="entry.EndDate" disabled="@CurrentFlags[index]" />
                </div>
                <div class="col-md-4 mb-3 d-flex align-items-end">
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="current-@index"
                               checked="@CurrentFlags[index]"
                               @onchange="e => { CurrentFlags[index] = (bool)(e.Value ?? false); if (CurrentFlags[index]) Entries[index].EndDate = null; }" />
                        <label class="form-check-label" for="current-@index">Current position</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2" @bind="entry.Description"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add Another Position</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public List<bool> CurrentFlags { get; set; } = new();
    [Parameter] public string? ValidationError { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
        CurrentFlags.Add(false);
    }

    private void RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
        CurrentFlags.RemoveAt(index);
    }
}

@using static sv_cf2e3316faa24278a6c6a6327c46adb2.Components.Pages.Apply.Apply

<h4 class="mb-3">References</h4>

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger">@ValidationError</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var r = References[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Reference @(index + 1)</h6>
                @if (References.Count > 2)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="r.Name" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="r.Relationship" />
                </div>
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="r.Email" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" @bind="r.Phone" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string? ValidationError { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }
}

@using static sv_cf2e3316faa24278a6c6a6327c46adb2.Components.Pages.Apply.Apply

<h4 class="mb-3">Review & Submit</h4>

@if (!string.IsNullOrEmpty(SubmitError))
{
    <div class="alert alert-danger">@SubmitError</div>
}

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@FullName</dd>
            <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Email</dd>
            <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Phone</dd>
            <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Address</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
    </div>
    <div class="card-body">
        @for (int i = 0; i < WorkEntries.Count; i++)
        {
            var entry = WorkEntries[i];
            var isCurrent = CurrentFlags[i];
            @if (i > 0) { <hr /> }
            <dl class="row mb-0">
                <dt class="col-sm-3">Company</dt><dd class="col-sm-9">@entry.Company</dd>
                <dt class="col-sm-3">Title</dt><dd class="col-sm-9">@entry.Title</dd>
                <dt class="col-sm-3">Period</dt>
                <dd class="col-sm-9">
                    @entry.StartDate.ToString("MMM yyyy") — @(isCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                </dd>
                <dt class="col-sm-3">Description</dt><dd class="col-sm-9">@(string.IsNullOrWhiteSpace(entry.Description) ? "—" : entry.Description)</dd>
            </dl>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
    </div>
    <div class="card-body">
        @for (int i = 0; i < References.Count; i++)
        {
            var r = References[i];
            @if (i > 0) { <hr /> }
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@r.Name</dd>
                <dt class="col-sm-3">Relationship</dt><dd class="col-sm-9">@r.Relationship</dd>
                <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@r.Email</dd>
                <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@r.Phone</dd>
            </dl>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space:pre-wrap;">@CoverLetter</p>
    </div>
</div>

<div class="d-flex justify-content-center mt-4">
    <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-2" role="status"></span>
            <span>Submitting…</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<bool> CurrentFlags { get; set; } = new();
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public string? SubmitError { get; set; }
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
}

