        var isCompleted = CompletedSteps.Contains(step);
        var isFuture = !isActive && !isCompleted;
        var clickable = isCompleted;

        <div class="step-item text-center flex-fill @(isActive ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
             role="button"
             @onclick="() => { if (clickable) OnStepClicked.InvokeAsync(step); }">
            <div class="step-circle mx-auto mb-1 @(isActive ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")">
                @if (isCompleted)
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@step</span>
                }
            </div>
            <small class="@(isFuture ? "text-muted" : isActive ? "fw-bold text-primary" : "text-success")">@stepNames[i]</small>
        </div>

        @if (step < stepNames.Length)
        {
            <div class="step-connector flex-fill" style="height:2px;max-width:40px;">
