@page "/apply"
@rendermode InteractiveServer
@using sv_cf2e3316faa24278a6c6a6327c46adb2.Models
@using sv_cf2e3316faa24278a6c6a6327c46adb2.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4">
    <h1 class="mb-4">Job Application</h1>

    @if (!_submitted)
    {
        <StepIndicator CurrentStep="_currentStep"
                       CompletedSteps="_completedSteps"
                       OnStepClicked="GoToStep" />

        <div class="card mt-4">
            <div class="card-body">
                @switch (_currentStep)
                {
                    case 1:
                        <StepPersonalInfo FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                                          FullNameChanged="v => _fullName = v"
                                          EmailChanged="v => _email = v"
                                          PhoneChanged="v => _phone = v"
                                          AddressChanged="v => _address = v"
                                          ValidationError="@_validationError"
                                          OnNext="NextFromPersonalInfo" />
                        break;

                    case 2:
                        <StepWorkHistory Entries="_workEntries"
                                         CurrentFlags="_currentJobFlags"
                                         ValidationError="@_validationError"
                                         OnBack="Back"
                                         OnNext="NextFromWorkHistory" />
                        break;

                    case 3:
                        <StepReferences References="_references"
                                        ValidationError="@_validationError"
                                        OnBack="Back"
                                        OnNext="NextFromReferences" />
                        break;

                    case 4:
                        <StepCoverLetter CoverLetter="@_coverLetter"
                                         CoverLetterChanged="v => _coverLetter = v"
                                         MaxLength="2000"
                                         OnBack="Back"
                                         OnNext="NextFromCoverLetter" />
                        break;

                    case 5:
                        <StepReview FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                                    WorkEntries="_workEntries" CurrentFlags="_currentJobFlags"
                                    References="_references" CoverLetter="@_coverLetter"
                                    IsSubmitting="_isSubmitting" SubmitError="@_submitError"
                                    OnEdit="GoToStep"
                                    OnSubmit="SubmitApplication" />
                        break;
                }
            </div>
        </div>
    }
    else
    {
        <div class="card mt-4">
            <div class="card-body text-center py-5">
                <div class="text-success mb-3" style="font-size:3rem;">✓</div>
                <h2 class="text-success">Application Submitted!</h2>
                <p class="lead mt-3">Your application has been received.</p>
                <p class="fs-5">Application ID: <strong>@_applicationId</strong></p>
                <p class="text-muted">Please save this ID for your records.</p>
            </div>
        </div>
    }
</div>

@code {
    private int _currentStep = 1;
    private HashSet<int> _completedSteps = new();

    // Step 1
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2
    private List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };
    private List<bool> _currentJobFlags = new() { false };

    // Step 3
    private List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4
    private string _coverLetter = "";

    // Shared
    private string? _validationError;
    private bool _isSubmitting;
    private string? _submitError;
    private bool _submitted;
    private int _applicationId;

    private void GoToStep(int step)
    {
        if (_completedSteps.Contains(step) || step == _currentStep)
        {
            _validationError = null;
            _currentStep = step;
        }
    }

    private void Back()
    {
        _validationError = null;
        _currentStep--;
    }

    private async Task NextFromPersonalInfo()
    {
        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email)
            || string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _validationError = "All fields are required.";
            return;
        }

        var emailValid = await ApplicationService.ValidateEmailAsync(_email);
        if (!emailValid)
        {
            _validationError = "Please enter a valid email address.";
            return;
        }

        _validationError = null;
        _completedSteps.Add(1);
        _currentStep = 2;
    }

    private void NextFromWorkHistory()
    {
        foreach (var entry in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title)
                || entry.StartDate == default)
            {
                _validationError = "Company, title, and start date are required for each position.";
                return;
            }
        }

        _validationError = null;
        _completedSteps.Add(2);
        _currentStep = 3;
    }

    private void NextFromReferences()
    {
        foreach (var r in _references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _validationError = "All fields are required for each reference.";
                return;
            }
        }

        _validationError = null;
        _completedSteps.Add(3);
        _currentStep = 4;
    }

    private void NextFromCoverLetter()
    {
        if (string.IsNullOrWhiteSpace(_coverLetter))
        {
            _validationError = "Cover letter is required.";
            return;
        }

        _validationError = null;
        _completedSteps.Add(4);
        _currentStep = 5;
    }

    private async Task SubmitApplication()
    {
        _isSubmitting = true;
        _submitError = null;

        try
        {
            var personal = new PersonalInfo(_fullName, _email, _phone, _address);
            var workHistory = new WorkHistory(_workEntries.Select((e, i) =>
                new WorkEntry(e.Company, e.Title, e.StartDate, _currentJobFlags[i] ? null : e.EndDate, e.Description)
            ).ToList());
            var refs = _references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var application = new JobApplication(personal, workHistory, refs, _coverLetter);

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public string Description { get; set; } = "";
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

