toolArgs.file_text:
@{
    var stepNames = new[] { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
}

<nav class="step-indicator d-flex align-items-center justify-content-between">
    @for (int i = 0; i < stepNames.Length; i++)
    {
        var step = i + 1;
        var isActive = step == CurrentStep;
        var isCompleted = CompletedSteps.Contains(step);
        var isFuture = !isActive && !isCompleted;
        var clickable = isCompleted;

        <div class="step-item text-center flex-fill @(isActive ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
             role="button"
             @onclick="() => { if (clickable) OnStepClicked.InvokeAsync(step); }">
            <div class="step-circle mx-auto mb-1 @(isActive ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")">
                @if (isCompleted)
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@step</span>
                }
            </div>
            <small class="@(isFuture ? "text-muted" : isActive ? "fw-bold text-primary" : "text-success")">@stepNames[i]</small>
        </div>

        @if (step < stepNames.Length)
        {
            <div class="step-connector flex-fill" style="height:2px;max-width:40px;">
                <hr class="m-0 @(CompletedSteps.Contains(step) ? "border-success" : "border-secondary")" style="border-width:2px;" />
            </div>
        }
    }
</nav>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

