@using static sv_cf2e3316faa24278a6c6a6327c46adb2.Components.Pages.Apply.Apply

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger">@ValidationError</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Position @(index + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Company <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="entry.Company" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="entry.Title" />
                </div>
            </div>

            <div class="row">
                <div class="col-md-4 mb-3">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" @bind="entry.StartDate" />
                </div>
                <div class="col-md-4 mb-3">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" @bind="entry.EndDate" disabled="@CurrentFlags[index]" />
                </div>
                <div class="col-md-4 mb-3 d-flex align-items-end">
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="current-@index"
                               checked="@CurrentFlags[index]"
                               @onchange="e => { CurrentFlags[index] = (bool)(e.Value ?? false); if (CurrentFlags[index]) Entries[index].EndDate = null; }" />
                        <label class="form-check-label" for="current-@index">Current position</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2" @bind="entry.Description"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add Another Position</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public List<bool> CurrentFlags { get; set; } = new();
    [Parameter] public string? ValidationError { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
        CurrentFlags.Add(false);
    }

    private void RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
        CurrentFlags.RemoveAt(index);
    }
}

@using static sv_cf2e3316faa24278a6c6a6327c46adb2.Components.Pages.Apply.Apply

<h4 class="mb-3">References</h4>

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger">@ValidationError</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var r = References[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Reference @(index + 1)</h6>
                @if (References.Count > 2)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="r.Name" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="r.Relationship" />
                </div>
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="r.Email" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" @bind="r.Phone" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string? ValidationError { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }
}

@using static sv_cf2e3316faa24278a6c6a6327c46adb2.Components.Pages.Apply.Apply

<h4 class="mb-3">Review & Submit</h4>

@if (!string.IsNullOrEmpty(SubmitError))
{
    <div class="alert alert-danger">@SubmitError</div>
}

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@FullName</dd>
            <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Email</dd>
            <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Phone</dd>
            <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Address</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
    </div>
    <div class="card-body">
        @for (int i = 0; i < WorkEntries.Count; i++)
        {
            var entry = WorkEntries[i];
            var isCurrent = CurrentFlags[i];
            @if (i > 0) { <hr /> }
            <dl class="row mb-0">
                <dt class="col-sm-3">Company</dt><dd class="col-sm-9">@entry.Company</dd>
                <dt class="col-sm-3">Title</dt><dd class="col-sm-9">@entry.Title</dd>
                <dt class="col-sm-3">Period</dt>
                <dd class="col-sm-9">
                    @entry.StartDate.ToString("MMM yyyy") — @(isCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                </dd>
                <dt class="col-sm-3">Description</dt><dd class="col-sm-9">@(string.IsNullOrWhiteSpace(entry.Description) ? "—" : entry.Description)</dd>
            </dl>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
    </div>
    <div class="card-body">
        @for (int i = 0; i < References.Count; i++)
        {
            var r = References[i];
            @if (i > 0) { <hr /> }
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@r.Name</dd>
                <dt class="col-sm-3">Relationship</dt><dd class="col-sm-9">@r.Relationship</dd>
                <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@r.Email</dd>
                <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@r.Phone</dd>
            </dl>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space:pre-wrap;">@CoverLetter</p>
    </div>
</div>

<div class="d-flex justify-content-center mt-4">
    <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-2" role="status"></span>
            <span>Submitting…</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<bool> CurrentFlags { get; set; } = new();
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public string? SubmitError { get; set; }
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
}
